import { createDiagnosticCollector, navigateProgram } from "@typespec/compiler";
import { createLinterRuleTester, expectDiagnostics, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { datasetSlicesDistinctRule } from "./dataset-slices-distinct.rule.js";

/**
 * Run the dataset-slices-distinct rule against a multi-file program using the raw runner.
 * This bypasses the LinterRuleTester's expectDiagnosticEmpty pre-check so that
 * multi-file programs with import statements can be used without import-ordering issues.
 */
async function runRule(
  runner: Awaited<ReturnType<typeof Tester.createInstance>>,
  code: string | Record<string, string>,
) {
  await runner.compileAndDiagnose(code);
  const collector = createDiagnosticCollector();
  const ruleId = `@a10n/blueprint-typespec/${datasetSlicesDistinctRule.name}`;
  const messages = datasetSlicesDistinctRule.messages as Record<string, any>;
  const context = {
    program: runner.program,
    reportDiagnostic(diag: { messageId?: string; format?: Record<string, string>; target: any }) {
      const msgDef = messages[diag.messageId ?? "default"];
      const messageStr = typeof msgDef === "string" ? msgDef : msgDef(diag.format ?? {});
      collector.add({ code: ruleId, severity: datasetSlicesDistinctRule.severity, message: messageStr, target: diag.target } as any);
    },
  };
  const listener = datasetSlicesDistinctRule.create(context as any);
  navigateProgram(runner.program, listener);
  return collector.diagnostics;
}

// Shared invariant + component scaffolding
const INVARIANT_FIXTURE = `
  @feature
  namespace Products.ReviewBot.Features.PrReview {
    @invariant(#{ predicate: "review has body", why: "quality" })
    op body_actionable(): void;
    @invariant(#{ predicate: "severity calibrated", why: "quality" })
    op severity_calibrated(): void;
    @invariant(#{ predicate: "diff parsed", why: "accuracy" })
    op diff_parsed(): void;
  }
`;

describe("dataset-slices-distinct rule", () => {
  let ruleTester: LinterRuleTester;
  let runner: Awaited<ReturnType<typeof Tester.createInstance>>;

  beforeEach(async () => {
    runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(runner, datasetSlicesDistinctRule, "@a10n/blueprint-typespec");
  });

  describe("valid", () => {
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_dataset_slices_distinct
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T017.T017_01
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_dataset_slices_distinct:Products.A10nBlueprintEngine.Features.DatasetAuthoring.dataset_slices_distinct:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_projects_targets_invariant:Products.A10nBlueprintEngine.Features.DatasetAuthoring.dataset_slices_distinct:must
    it("T017_01: two @dataset ops with different @projects sets in the same file — no diagnostic", async () => {
      await ruleTester
        .expect(`
          ${INVARIANT_FIXTURE}

          @component(#{ type: ComponentType.Agent })
          namespace Components.ReviewAgent {
            @dataset(#{ title: "Dataset A" })
            @projects(Products.ReviewBot.Features.PrReview.body_actionable)
            op d001_dataset_a(): void;

            @dataset(#{ title: "Dataset B" })
            @projects(Products.ReviewBot.Features.PrReview.severity_calibrated)
            op d002_dataset_b(): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T017.T017_02
    it("T017_02: single @dataset op — no diagnostic", async () => {
      await ruleTester
        .expect(`
          ${INVARIANT_FIXTURE}

          @component(#{ type: ComponentType.Agent })
          namespace Components.ReviewAgent {
            @dataset(#{ title: "Only dataset" })
            @projects(Products.ReviewBot.Features.PrReview.body_actionable)
            op d001_only(): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T017.T017_03
    it("T017_03: identical @projects sets in DIFFERENT files — no diagnostic (different files are allowed)", async () => {
      const diags = await runRule(runner, {
        "main.tsp": `
import "./file_a.tsp";
import "./file_b.tsp";`,
        "file_a.tsp": `
import "@a10n/blueprint-typespec";
using State;
@feature
namespace Products.ReviewBot.Features.PrReview {
  @invariant(#{ predicate: "review has body", why: "quality" })
  op body_actionable(): void;
}
@component(#{ type: ComponentType.Agent })
namespace Components.ReviewAgent;
@dataset(#{ title: "Dataset A" })
@projects(Products.ReviewBot.Features.PrReview.body_actionable)
op d001_dataset_a(): void;`,
        "file_b.tsp": `
import "@a10n/blueprint-typespec";
using State;
namespace Components.ReviewAgent;
@dataset(#{ title: "Dataset B" })
@projects(Products.ReviewBot.Features.PrReview.body_actionable)
op d002_dataset_b(): void;`,
      });
      expectDiagnostics(diags, []);
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T017.T017_04
    it("T017_04: two @dataset ops with identical @projects sets in same file — fires diagnostic on second", async () => {
      await ruleTester
        .expect(`
          ${INVARIANT_FIXTURE}

          @component(#{ type: ComponentType.Agent })
          namespace Components.ReviewAgent {
            @dataset(#{ title: "Dataset A" })
            @projects(Products.ReviewBot.Features.PrReview.body_actionable)
            op d001_dataset_a(): void;

            // a10n:blueprint:ignore
            @dataset(#{ title: "Dataset B same targets" })
            @projects(Products.ReviewBot.Features.PrReview.body_actionable)
            op d002_dataset_b(): void;
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/dataset-slices-distinct",
          message: /d002_dataset_b/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T017.T017_05
    it("T017_05: two @dataset ops with identical multi-invariant @projects sets in same file — fires diagnostic", async () => {
      await ruleTester
        .expect(`
          ${INVARIANT_FIXTURE}

          @component(#{ type: ComponentType.Agent })
          namespace Components.ReviewAgent {
            @dataset(#{ title: "Dataset A" })
            @projects(
              Products.ReviewBot.Features.PrReview.body_actionable,
              Products.ReviewBot.Features.PrReview.severity_calibrated
            )
            op d001_dataset_a(): void;

            // a10n:blueprint:ignore
            @dataset(#{ title: "Dataset B duplicate" })
            @projects(
              Products.ReviewBot.Features.PrReview.severity_calibrated,
              Products.ReviewBot.Features.PrReview.body_actionable
            )
            op d002_dataset_b(): void;
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/dataset-slices-distinct",
          message: /d002_dataset_b/,
        });
    });
  });
});
